export class OpenAI{constructor(t){this.model=t}url(){return`https://oai.toolbomber.com/${this.model}`}static async getResponse(t,e="gpt3"){const o=new OpenAI(e);return await o.getResponse(t)}async getResponse(t){const e={method:"POST",headers:{"Content-Type":"text/plain"},body:t};try{const t=await fetch(this.url(),e);return await t.text()}catch(t){console.error("Error: ",t)}}}